import{_ as e,o as t,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-01.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-01.md"}'),n={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-01.md"};function s(l,r,i,h,g,p){return t(),a("div",null,[...r[0]||(r[0]=[o('<p>🫘 黃豆追蹤日報 — 2026年6月1日（週一）</p><blockquote><p><strong>查詢時間</strong>：TST 06:02 (2026-06-01 06:02 = 2026-05-31 22:02 UTC) <strong>昨日敘事延續</strong>：Trump 拒絕伊朗 MoU（第3輪修改）→ 封鎖持續 → CBOT 1,186.75 → 種植進度超前 → 聖嬰預警持續 → COMPUTEX 本週開幕</p></blockquote><hr><h2 id="📊-8項指標檢查" tabindex="-1">📊 8項指標檢查 <a class="header-anchor" href="#📊-8項指標檢查" aria-label="Permalink to &quot;📊 8項指標檢查&quot;">​</a></h2><h3 id="指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-本週更新在即" tabindex="-1">指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（本週更新在即） <a class="header-anchor" href="#指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-本週更新在即" aria-label="Permalink to &quot;指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（本週更新在即）&quot;">​</a></h3><p>截至 5/24，美國黃豆種植完成度 <strong>79%</strong>（5年平均 53%，去年 68%）。Emergence 49%（5年平均 40%）。各州細分：</p><ul><li>Iowa 90%、Minnesota 90%、Illinois 84%、Missouri 85%、Nebraska 82%</li><li>Wisconsin 從 28%→54%（一週跳升 26%）</li><li>Michigan 37%（仍落後5年平均 46%）</li><li>North Dakota 45%、South Dakota 58%、Kansas 56%</li></ul><p><strong>與昨日比較</strong>：無變化。<strong>本週 6/2（明日）將公布新一份 Crop Progress 報告</strong>（Memorial Day 延後），是重要觀察點。種植進度持續超前，Michigan 部分仍落後。</p><p>📎 來源：<a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a> · <a href="https://www.brownfieldagnews.com/news/86-of-u-s-corn-79-of-soybeans-planted/" target="_blank" rel="noreferrer">Brownfield Ag News</a> （T: 06:02 TST）</p><hr><h3 id="指標2️⃣-巴西供應-—-🟢-持續擴張-無重大變化" tabindex="-1">指標2️⃣ 巴西供應 — 🟢 持續擴張（無重大變化） <a class="header-anchor" href="#指標2️⃣-巴西供應-—-🟢-持續擴張-無重大變化" aria-label="Permalink to &quot;指標2️⃣ 巴西供應 — 🟢 持續擴張（無重大變化）&quot;">​</a></h3><p>巴西收割順利，出口保持強勁。USDA WASDE 預測 2026-27 年度全球油籽產量增長。巴西豐收持續壓制國際價格上行空間，但荷莫茲封鎖推高替代航線運費。</p><p><strong>與昨日比較</strong>：無重大變化。CONAB 月度報告待公布。</p><p>📎 來源：<a href="https://www.farmprogress.com/marketing/soybean-futures-surge-as-usda-forecasts-tighter-supplies" target="_blank" rel="noreferrer">Farm Progress</a> · <a href="https://www.brecorder.com/news/40419969/brazils-soy-area-to-grow-marginally-in-202627" target="_blank" rel="noreferrer">Brecorder</a> （T: 06:02 TST）</p><hr><h3 id="指標3️⃣-尿素價格-多單訊號-—-🟡-從高點修正後穩定" tabindex="-1">指標3️⃣ 尿素價格 + 多單訊號 — 🟡 從高點修正後穩定 <a class="header-anchor" href="#指標3️⃣-尿素價格-多單訊號-—-🟡-從高點修正後穩定" aria-label="Permalink to &quot;指標3️⃣ 尿素價格 + 多單訊號 — 🟡 從高點修正後穩定&quot;">​</a></h3><p><strong>最新報價（5/29）</strong>：</p><ul><li>TradingEconomics 全球尿素指數：$447.50/噸（月跌 -34.39%，年漲 +23.45%）</li><li>3月曾因荷莫茲危機飆至 $725.6/噸（+53.7% m/m），後大幅修正</li><li>全球化肥價格預計 2026 年上漲超 30%</li><li>美國墨西哥灣 FOB：$558.98/噸</li></ul><p><strong>關鍵變化</strong>：尿素從封鎖高峰 $940 修正至 $447.50 → 修正幅度 -52%。但全球化肥危機仍未解除（1/3 全球化肥供應受威脅）。Trump 拒絕 MoU → 封鎖持續 → 化肥供應風險仍存。</p><p><strong>與昨日比較</strong>：無重大變化。尿素穩定在 $447.50 區間。</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/urea" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://rzzro.com/news-insights/urea-hormuz-crisis-may-2026.html" target="_blank" rel="noreferrer">Rzzro</a> （T: 06:02 TST）</p><hr><h3 id="指標4️⃣-荷莫茲海峽通航狀態-—-🔴-封鎖持續-第3輪修改不確定" tabindex="-1">指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 封鎖持續 + 第3輪修改不確定 <a class="header-anchor" href="#指標4️⃣-荷莫茲海峽通航狀態-—-🔴-封鎖持續-第3輪修改不確定" aria-label="Permalink to &quot;指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 封鎖持續 + 第3輪修改不確定&quot;">​</a></h3><p><strong>6/1 最新</strong>：</p><ul><li><strong>Trump 拒絕原始 MoU，送出第3輪修訂版</strong>：重點修訂荷莫茲條款 + 高濃縮鈾移除</li><li><strong>伊朗尚未回覆</strong>第3輪修改 → 不確定性延長</li><li><strong>美軍封鎖仍在</strong>：Trump 表示「不急」</li><li><strong>實際通航</strong>：維持低檔（~23 艘/日，戰前 125-140 艘/日）</li><li><strong>以色列-真主黨升級</strong>：Beaufort 城堡陷落 → 中東風險溢價回升</li></ul><p><strong>對黃豆影響</strong>：</p><ul><li>封鎖持續 → 化肥供應緊繃 → 種植成本壓力</li><li>但尿素已從 $940 回落至 $447 → 壓力有所緩解</li><li><strong>當前狀態</strong>：第3輪修改後的不確定性 → 市場在 hope 與 fear 間拉鋸</li></ul><p>📎 來源：<a href="https://www.cbsnews.com/live-updates/iran-war-us-trump-vance-ceasefire-strait-of-hormuz-deal-close" target="_blank" rel="noreferrer">CBS News</a> · <a href="https://www.chosun.com/english/world-en/2026/06/01/5WW2C5G6OFFM5C4B34WCCHQGTE" target="_blank" rel="noreferrer">Chosun</a> （T: 06:02 TST）</p><hr><h3 id="指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" tabindex="-1">指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展） <a class="header-anchor" href="#指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" aria-label="Permalink to &quot;指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展）&quot;">​</a></h3><ul><li>中國承諾 2026-28 年每年至少購買 2,500 萬噸美國黃豆</li><li>白宮事實清單：中國將額外購買每年至少 $170 億美元美國農產品</li><li>2026年前兩個月美國對中黃豆出口 +79.66%</li><li><strong>但</strong>：2025年3月至2026年2月，美國對中農產品出口下降 $149 億（黃豆佔一半）</li><li><strong>關稅影響</strong>：中國對美黃豆仍維持 10% 附加關稅（+10% 基準關稅 = 20% 差異）</li><li><strong>農民 skepticism</strong>：北京未即時確認 $170 億金額</li></ul><p><strong>與昨日比較</strong>：無新進展。北京仍未正式確認承諾金額。</p><p>📎 來源：<a href="https://www.scmp.com/economy/global-economy/article/3353803/soybean-counters-scope-china-us-farm-deal-depends-math-analysts-say" target="_blank" rel="noreferrer">SCMP</a> · <a href="https://farmpolicynews.illinois.edu/2026/05/chinas-retaliatory-tariffs-cost-us-ag-exporters-15-billion-study-says/" target="_blank" rel="noreferrer">Farm Policy News</a> （T: 06:02 TST）</p><hr><h3 id="指標6️⃣-天然氣價格-—-🟢-微升但穩定" tabindex="-1">指標6️⃣ 天然氣價格 — 🟢 微升但穩定 <a class="header-anchor" href="#指標6️⃣-天然氣價格-—-🟢-微升但穩定" aria-label="Permalink to &quot;指標6️⃣ 天然氣價格 — 🟢 微升但穩定&quot;">​</a></h3><ul><li>Henry Hub 現貨（5/29）：~$3.29/MMBtu（+0.97%）</li><li>5月走勢：$2.52（4月底）→ $3.29（5/29）</li><li>天然氣是氮肥生產原料，目前價格穩定，影響有限</li></ul><p><strong>與昨日比較</strong>：無重大變化。</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.aga.org/research-policy/resource-library/natural-gas-market-indicators-may-28-2026/" target="_blank" rel="noreferrer">AGA</a> （T: 06:02 TST）</p><hr><h3 id="指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-超級聖嬰預警持續" tabindex="-1">指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 超級聖嬰預警持續 <a class="header-anchor" href="#指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-超級聖嬰預警持續" aria-label="Permalink to &quot;指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 超級聖嬰預警持續&quot;">​</a></h3><p><strong>最新更新</strong>：全球氣候正從拉尼娜過渡至強聖嬰事件（Super El Niño），預計北半球夏季形成。</p><ul><li><strong>NOAA 預測</strong>：2026年10-12月有 ~1/3 機率形成「超級聖嬰」（海溫偏高 &gt;2°C）</li><li><strong>對黃豆影響</strong>： <ul><li>美國：正面（+4% 產量），中西部夏季降雨增加</li><li>巴西：負面，南部洪水 + 北部/東北部乾旱風險</li><li>阿根廷：正面（+2% 產量）</li></ul></li><li><strong>歷史參考</strong>：2015-16 超級聖嬰 → 巴西糧食產量 -9.5%</li></ul><p><strong>與昨日比較</strong>：無變化。聖嬰預警持續。</p><p>📎 來源：<a href="https://badgercropnetwork.com/soybean-yield-and-the-2026-super-el-nino-what-growers-need-to-know/" target="_blank" rel="noreferrer">Badger Crop Network</a> · <a href="https://en.clickpetroleoegas.com.br/study-reveals-that-el-nino-is-gaining-strength-in-the-pacific-favoring-the-soybean-crop-in-the-united-states-in-2026-and-increasing-the-risk-hl1402/" target="_blank" rel="noreferrer">Click Petroleum</a> （T: 06:02 TST）</p><hr><h3 id="指標8️⃣-cbot-黃豆期貨價格區間-—-🟡-小幅回落但仍穩健" tabindex="-1">指標8️⃣ CBOT 黃豆期貨價格區間 — 🟡 小幅回落但仍穩健 <a class="header-anchor" href="#指標8️⃣-cbot-黃豆期貨價格區間-—-🟡-小幅回落但仍穩健" aria-label="Permalink to &quot;指標8️⃣ CBOT 黃豆期貨價格區間 — 🟡 小幅回落但仍穩健&quot;">​</a></h3><p><strong>最新報價（5/29 收盤）</strong>：</p><ul><li>CBOT 7月黃豆（ZSN26）：1,186.75 ¢/bu（-0.65%）</li><li>11月新作（SX26）：1,196 ¢ 開盤，日內 1,186-1,199</li><li>30日區間：1,099.25 - 1,235.00 ¢/bu</li><li><strong>USDA WASDE 預測</strong>：2026/27 年度均價 $11.40/bu（高於 2025/26 的 $10.40）</li><li><strong>新作 November</strong>：突破 $12/bu 關卡（WASDE 後）</li><li><strong>現貨</strong>：Iowa 均價 $11.23/bu，Minneapolis 1,134.75-1,138.75 ¢/bu</li><li><strong>出口承諾</strong>：39.371 MMT，年減 -18%</li></ul><p><strong>注意</strong>：06:02 TST 週一，CME 期貨尚未開盤（09:00 ET 開盤），此為 5/29 收盤數據</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.marketwatch.com/investing/future/sx26" target="_blank" rel="noreferrer">MarketWatch</a> · <a href="https://www.ers.usda.gov/topics/crops/soybeans-and-oil-crops/market-outlook" target="_blank" rel="noreferrer">USDA ERS</a> （T: 06:02 TST）</p><hr><h2 id="📰-黃豆即時新聞-5-則" tabindex="-1">📰 黃豆即時新聞 5 則 <a class="header-anchor" href="#📰-黃豆即時新聞-5-則" aria-label="Permalink to &quot;📰 黃豆即時新聞 5 則&quot;">​</a></h2><ol><li><p><strong>[5/31] Trump 拒絕伊朗 MoU 第3輪修改 — 封鎖持續不確定性延長</strong> Trump rejected the original MoU and sent a 3rd revision focusing on Hormuz reopening terms and highly enriched uranium removal. Iran has not yet responded. Trump says he&#39;s in &quot;no hurry.&quot; 📎 <a href="https://www.cbsnews.com/live-updates/iran-war-us-trump-vance-ceasefire-strait-of-hormuz-deal-close" target="_blank" rel="noreferrer">CBS News</a> · <a href="https://www.chosun.com/english/world-en/2026/06/01/5WW2C5G6OFFM5C4B34WCCHQGTE" target="_blank" rel="noreferrer">Chosun</a></p></li><li><p><strong>[5/29] CBOT 農產品回落：黃豆 -0.65%，油價壓力</strong> Soybeans fell to 1,186.75 as crude oil dropped below $88, pressuring the ag complex. November futures opened at 1,196, traded 1,186-1,199. 📎 <a href="https://www.marketwatch.com/investing/future/sx26" target="_blank" rel="noreferrer">MarketWatch</a></p></li><li><p><strong>[5/27] USDA WASDE：2026/27 黃豆均價 $11.40/bu，新作突破 $12</strong> May WASDE projected 2026/27 U.S. season-average farm price at $11.40/bu, up from $10.40 for 2025/26. November futures surged above $12 benchmark. 📎 <a href="https://www.ers.usda.gov/topics/crops/soybeans-and-oil-crops/market-outlook" target="_blank" rel="noreferrer">USDA ERS</a></p></li><li><p><strong>[5/26] USDA Crop Progress：黃豆 79%（5年平均 53%）</strong> Soybean planting 79% complete vs 5-year avg 53%. Emergence 49% vs avg 40%. Next report due 6/2. 📎 <a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a></p></li><li><p><strong>[5/22] 中國報復性關稅致美國農產品損失 $149 億</strong> China&#39;s retaliatory tariffs cost US ag exporters $14.9 billion over 12 months. Soybeans accounted for $6.8 billion. 📎 <a href="https://farmpolicynews.illinois.edu/2026/05/chinas-retaliatory-tariffs-cost-us-ag-exporters-15-billion-study-says/" target="_blank" rel="noreferrer">Farm Policy News</a></p></li></ol><hr><h2 id="🔮-情景分析" tabindex="-1">🔮 情景分析 <a class="header-anchor" href="#🔮-情景分析" aria-label="Permalink to &quot;🔮 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>黃豆價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>伊朗接受第3輪修改 + 荷莫茲重開</td><td>25%</td><td>-5~10%</td><td>化肥供應恢復 + 運費正常化 + 油價下跌</td></tr><tr><td>第3輪修改後雙方拉鋸延後</td><td>45%</td><td>+0~3%</td><td>化肥成本從高點回落但維持，種植進度超前抵消</td></tr><tr><td>伊朗拒絕 + 衝突升級</td><td>20%</td><td>+10~15%</td><td>化肥斷供 + 運費飆升 + 油價再漲</td></tr><tr><td>超級聖嬰 + 化肥危機雙重夾擊</td><td>10%</td><td>+15~25%</td><td>全球糧食危機、生物燃料需求激增</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-29): Soybeans 1,186.75 ¢/bu, Urea $447.50</li><li>MarketWatch (2026-05-29): SX26 1,196 open, 1,186-1,199 range</li><li>USDA ERS (2026-05): WASDE 2026/27 farm price $11.40/bu</li><li>DTN/PF (2026-05-26): USDA Crop Progress – Soybeans 79%</li><li>CBS News (2026-05/31): Trump 3rd revision to MoU</li><li>Chosun (2026-06-01): Trump rejects Iran MoU</li><li>SCMP (2026): China $17B ag commitment</li><li>Farm Policy News (2026-05-22): China tariffs cost $14.9B</li><li>Badger Crop Network (2026): Super El Niño soybean impact</li><li>Rzzro (2026): Urea $725.6 peak in March, +53.7%</li></ol>',59)])])}const u=e(n,[["render",s]]);export{d as __pageData,u as default};
